CREATE OR REPLACE VIEW V_MOVIMIENTO AS 
SELECT TIPOMOVIMIENTO.CLASE, TIPOMOVIMIENTO.CONCEPTO CONCEPTO_TIPOMOVI, MOVIMIENTO."COMPANIA",MOVIMIENTO."TIPOMOVIMIENTO",MOVIMIENTO."NUMERO",MOVIMIENTO."TERCERO",MOVIMIENTO."SUCURSAL",MOVIMIENTO."CONCEPTO",MOVIMIENTO."FECHA",MOVIMIENTO."RESPONSABLE_ORIGEN",MOVIMIENTO."SUCURSAL_RESORIGEN",MOVIMIENTO."RESPONSABLE_DESTINO",MOVIMIENTO."SUCURSAL_RESDESTINO",MOVIMIENTO."BODEGA_ORIGEN",MOVIMIENTO."BODEGA_DESTINO",MOVIMIENTO."HORA",MOVIMIENTO."DESCRIPCION",MOVIMIENTO."PORCIVAGLOBAL",MOVIMIENTO."TIPOMOVASOCIADO",MOVIMIENTO."MOVASOCIADO",MOVIMIENTO."FECHAMOVASOCIADO",MOVIMIENTO."VALORIVA",MOVIMIENTO."VALORDESCUENTO",MOVIMIENTO."VALORTOTAL",MOVIMIENTO."VACIA",MOVIMIENTO."CENTRODECOSTO",MOVIMIENTO."REMISIONNO",MOVIMIENTO."FACTURANO",MOVIMIENTO."VALORDOCASOCIADO",MOVIMIENTO."AJUSTECENTAVOS",MOVIMIENTO."AJUSTECENTAVOS1",MOVIMIENTO."REGISTRADO",MOVIMIENTO."IMPRESO",MOVIMIENTO."GENERADO",MOVIMIENTO."AUXILIAR",MOVIMIENTO."TOTALCONAJUSTE",MOVIMIENTO."PROVEEDORCA",MOVIMIENTO."SUCURSALCA",MOVIMIENTO."VALORTOTALCONIVA",MOVIMIENTO."FINICIO_CONTRATO",MOVIMIENTO."FFINAL_CONTRATO",MOVIMIENTO."AJUSTE_DEC_MANUAL",MOVIMIENTO."CREATED_BY",MOVIMIENTO."DATE_CREATED",MOVIMIENTO."MODIFIED_BY",MOVIMIENTO."DATE_MODIFIED",MOVIMIENTO."CLASE_BODEGA_ORIGEN",MOVIMIENTO."CLASE_BODEGA_DESTINO",MOVIMIENTO."DEPENDENCIA_ORIGEN",MOVIMIENTO."DEPENDENCIA_DESTINO",MOVIMIENTO."ANO"
FROM TIPOMOVIMIENTO INNER JOIN MOVIMIENTO 
  ON TIPOMOVIMIENTO.COMPANIA = MOVIMIENTO.COMPANIA
 AND TIPOMOVIMIENTO.CODIGO = MOVIMIENTO.TIPOMOVIMIENTO
WHERE NOT ((TIPOMOVIMIENTO.CLASE='D' AND TIPOMOVIMIENTO.CONCEPTO IN('DT','L')) --EXCLUIR LOS DESCARGO DE BODEGA
     OR  (TIPOMOVIMIENTO.CLASE='T' AND TIPOMOVIMIENTO.CONCEPTO IN('T','DS','L'))--EXCLUIR LOS TRASLADOS
     )
 
;